import numpy as np

def sarsa(n_states: int, n_episodes: int, alpha: float, gamma: float, epsilon: float) -> np.ndarray:
    Q = np.zeros((n_states, 2))
    goal = n_states - 1

    def choose_action(s):
        if np.random.random() < epsilon:
            return np.random.randint(2)
        return int(np.argmax(Q[s]))

    for _ in range(n_episodes):
        s = 0
        a = choose_action(s)

        while s != goal:
            s_next = int(np.clip(s + (1 if a == 1 else -1), 0, goal))
            r = 1.0 if s_next == goal else 0.0
            a_next = choose_action(s_next)

            Q[s, a] += alpha * (r + gamma * Q[s_next, a_next] - Q[s, a])
            s, a = s_next, a_next

    return Q
